+// packages/common/messaging.js — Message queue abstraction (intentional bug: wrong content type)
+export function createQueue() {
+  const messages = [];
+  return {
+    name: 'task-queue',
+    // BUG: queue endpoint typo
+    endpoint: 'amqp://queue-svc:5672',
+    connected: false,
+    connect() {
+      console.log(`Connecting to queue at ${this.endpoint}...`);
+      this.connected = true;
+      return true;
+    },
+    publish(queue, payload) {
+      if (!this.connected) throw new Error('Not connected to queue');
+      // BUG: doesn't validate payload shape
+      messages.push({ queue, payload, timestamp: Date.now() });
+      return true;
+    },
+    consume(queue) {
+      if (!this.connected) throw new Error('Not connected to queue');
+      const idx = messages.findIndex(m => m.queue === queue);
+      if (idx === -1) return null;
+      return messages.splice(idx, 1)[0];
+    },
+    // BUG: should return pending messages, but throws on empty
+    getPendingCount(queue) {
+      return messages.filter(m => m.queue === queue).length;
+    },
+    disconnect() {
+      this.connected = false;
+    }
+  };
+}
